import { isNonEmptyRange } from './type-guards.js';
import { formatValueRange, getSingleValue } from './value-formatters.js';
import type { HeaderData } from '../../../types.js';

export const dotFormatterStrategy = (value: HeaderData) => {
  if (isNonEmptyRange(value)) {
    return formatValueRange(value);
  }

  const returnValue = getSingleValue(value);
  return returnValue.toString();
};
